userDefinedLinkHintCss:
div > .vimiumHintMarker {
    background: #1e1e2e;
    box-shadow: 1px 1px 3px #31324499;
    border: none;
    border-radius: 3px;
    padding: 2px 2px 0 3px;

    & span {
        color: #dce2f5;
        font-family: monospace;
        font-size: 11px;
        font-weight: 900;
        text-shadow: none;
        letter-spacing: 1px;
    }

    & > .matchingCharacter {
        color: #cba6f7;
    }
}

div#hud-container {
    visibility: collapse;
}
